import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.BpLU1RrG.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1777870846000}'),r={name:"getting-started/index.md"};function i(d,e,s,l,c,u){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>validup</strong> is a composable, path-based validation library for TypeScript. It picks a deliberate point between schema DSLs (which bake in every rule) and hand-rolled validators (which tangle parsing, validation, and transformation):</p><blockquote><p>Mount any validator function onto any path of any input, compose containers, and let the runtime handle path expansion, group filtering, and error aggregation.</p></blockquote><p>You bring the validators (or wrap an existing library through an integration package); validup orchestrates them.</p><h2 id="three-nouns-one-verb" tabindex="-1">Three nouns, one verb <a class="header-anchor" href="#three-nouns-one-verb" aria-label="Permalink to &quot;Three nouns, one verb&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Noun</th><th>Role</th></tr></thead><tbody><tr><td><code>Container</code></td><td>A bag of mounts. Mount a validator on a path, mount another container at a sub-path, run the whole graph.</td></tr><tr><td><code>Validator</code></td><td>A function `(ctx) =&gt; value</td></tr><tr><td><code>Issue</code></td><td>A discriminated record (<code>item</code> or <code>group</code>) with <code>path</code>, <code>message</code>, <code>code</code>, optional <code>expected</code>/<code>received</code>.</td></tr></tbody></table><p>The verb is <code>container.run(data)</code> (with <code>runSync</code>, <code>runParallel</code>, <code>safeRun</code>, <code>safeRunSync</code> siblings). On failure it throws a <code>ValidupError</code> carrying the collected <code>Issue[]</code>.</p><h2 id="when-to-use-validup" tabindex="-1">When to use validup <a class="header-anchor" href="#when-to-use-validup" aria-label="Permalink to &quot;When to use validup&quot;">​</a></h2><ul><li>You need to mount <strong>per-path</strong> validation rules without committing to one schema library.</li><li>You want to <strong>compose</strong> small, testable validators rather than write one giant schema.</li><li>You already use a validator (zod, express-validator, valibot, arktype) and want a shared <strong>path/group/issue</strong> model on top of it.</li><li>You want a <strong>typed user context</strong> flowing through nested mounts (<code>Container&lt;T, C&gt;</code>).</li><li>You want a single model that drives both server-side parsing and a Vue 3 reactive form.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/getting-started/installation">Installation</a> — install the core and any integration packages.</li><li><a href="/getting-started/quick-start">Quick Start</a> — compose a Container, run it, handle errors.</li><li><a href="/guide/container">Guide → Container</a> — the full mount semantics.</li><li><a href="/integrations/">Integrations</a> — pick a bridge to zod, express-validator, Routup, or Vue.</li></ul>',11)])])}const g=t(r,[["render",i]]);export{p as __pageData,g as default};
